        "q": "#event_simpleName=DriverLoad\n| groupBy([ImageFileName, SHA256HashData, ComputerName])\n| groupBy([ImageFileName, SHA256HashData], function=count(as=hosts))\n| hosts<3\n| sort(hosts, order=asc)"
